const response = $input.item.json?.output ?? JSON.stringify($input.item.json);

let threshold = null;
let reasoning = 'Keine Begründung';

try {
  // JSON aus Claude-Antwort extrahieren
  const match = response.match(/\{[\s\S]*?"threshold_ct"[\s\S]*?\}/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    threshold = parseFloat(parsed.threshold_ct);
    reasoning = parsed.reasoning ?? reasoning;
  }
} catch (e) {
  // Fallback: Zahl direkt suchen
  const numMatch = response.match(/threshold_ct[":\s]+(\d+\.?\d*)/);
  if (numMatch) threshold = parseFloat(numMatch[1]);
}

if (threshold === null || isNaN(threshold)) {
  throw new Error('Claude-Response nicht parsebar: ' + String(response).slice(0, 300));
}

threshold = Math.min(50, Math.max(0, threshold));

return [{ json: { threshold_ct: threshold, reasoning, timestamp: new Date().toISOString(), raw: String(response).slice(0, 500) } }];
